// Custom error class for cycle detection
export class CycleDetectedError extends Error {
  constructor(message: string = "Cycle detected in graph") {
    super(message);
    this.name = "CycleDetectedError";
  }
}

// Type for the graph (adjacency list)
export type Graph<T> = Map<T, Set<T>>;

// Function to perform topological sort
export function topologicalSort<T>(
  nodes: T[],
  edges: Array<[T, T]>
): T[] {
  // Build adjacency list and calculate in-degrees
  const graph: Graph<T> = new Map();
  const inDegree = new Map<T, number>();

  // Initialize all nodes with empty adjacency sets and zero in-degree
  for (const node of nodes) {
    graph.set(node, new Set());
    inDegree.set(node, 0);
  }

  // Process edges to build the graph and track in-degrees
  for (const [from, to] of edges) {
    graph.get(from)?.add(to);
    inDegree.set(to, (inDegree.get(to) ?? 0) + 1);
  }

  // Use Kahn's algorithm: start with nodes that have no incoming edges
  const queue: T[] = [];
  for (const node of nodes) {
    if (inDegree.get(node) === 0) {
      queue.push(node);
    }
  }

  const sorted: T[] = [];
  while (queue.length > 0) {
    const current = queue.shift()!;
    sorted.push(current);

    // Reduce in-degree for all neighbors
    for (const neighbor of graph.get(current)!) {
      inDegree.set(neighbor, inDegree.get(neighbor)! - 1);
      if (inDegree.get(neighbor) === 0) {
        queue.push(neighbor);
      }
    }
  }

  // If we couldn't process all nodes, there's a cycle
  if (sorted.length !== nodes.length) {
    throw new CycleDetectedError();
  }

  return sorted;
}
```

This implementation uses Kahn's algorithm to perform the topological sort. It initializes the graph with all nodes and their in-degrees, then processes nodes with zero in-degree, reducing the in-degree of their neighbors. If the final sorted array doesn't contain all nodes, a cycle must exist and we throw the error. be fine since all nodes are included in the initial processing. The implementation handles empty inputs correctly—an empty nodes array produces an empty result, and edges without nodes are validated upfront. Self-loops naturally trigger cycle detection since a node's in-degree won't reach zero. I'm confident this approach covers the necessary cases.

